const express = require('express');
const redis = require('redis');
const crypto = require('crypto');
const app = express();
app.use(express.json());

const redisClient = redis.createClient({
  host: 'localhost',
  port: 6379
});

const CLIENTS = {
  'client1': 'secret1'
};

const USERS = {
  'user1': 'password1'
};

const ACCESS_TOKEN_EXPIRY = 3600; // 1 hour
const REFRESH_TOKEN_EXPIRY = 31536000; // 1 year

// Generate secure random token
function generateToken(length = 32) {
  return crypto.randomBytes(length).toString('hex');
}

// Validate client credentials
function validateClient(clientId, clientSecret) {
  return CLIENTS[clientId] && CLIENTS[clientId] === clientSecret;
}

// Validate user credentials
function validateUser(username, password) {
  return USERS[username] && USERS[username] === password;
}

// Issue refresh token
async function issueRefreshToken(userId) {
  const refreshToken = generateToken(64);
  const tokenData = {
    userId: userId,
    createdAt: Date.now(),
    used: false
  };
  
  await redisClient.setex(`refresh:${refreshToken}`, REFRESH_TOKEN_EXPIRY, JSON.stringify(tokenData));
  return refreshToken;
}

// Issue access token
async function issueAccessToken(userId) {
  const accessToken = generateToken(64);
  const tokenData = {
    userId: userId,
    createdAt: Date.now(),
    expiresAt: Date.now() + (ACCESS_TOKEN_EXPIRY * 1000)
  };
  
  await redisClient.setex(`access:${accessToken}`, ACCESS_TOKEN_EXPIRY, JSON.stringify(tokenData));
  return accessToken;
}

// Validate refresh token
async function validateRefreshToken(refreshToken) {
  const tokenData = await redisClient.get(`refresh:${refreshToken}`);
  if (!tokenData) return null;
  
  const data = JSON.parse(tokenData);
  return data;
}

// Exchange refresh token for new tokens
app.post('/oauth/token', async (req, res) => {
  try {
    const { grant_type, client_id, client_secret, refresh_token, username, password } = req.body;
    
    if (grant_type === 'refresh_token') {
      if (!refresh_token) {
        return res.status(400).json({ error: 'invalid_request', error_description: 'Refresh token is required' });
      }
      
      const tokenData = await validateRefreshToken(refresh_token);
      if (!tokenData) {
        return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid refresh token' });
      }
      
      // Reuse refresh token without rotation
      const newAccessToken = await issueAccessToken(tokenData.userId);
      const newRefreshToken = refresh_token; // Reuse same refresh token
      
      return res.json({
        access_token: newAccessToken,
        token_type: 'Bearer',
        expires_in: ACCESS_TOKEN_EXPIRY,
        refresh_token: newRefreshToken
      });
    }
    
    if (grant_type === 'password') {
      if (!validateClient(client_id, client_secret)) {
        return res.status(400).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
      }
      
      if (!validateUser(username, password)) {
        return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid username or password' });
      }
      
      const userId = username;
      const accessToken = await issueAccessToken(userId);
      const refreshToken = await issueRefreshToken(userId);
      
      return res.json({
        access_token: accessToken,
        token_type: 'Bearer',
        expires_in: ACCESS_TOKEN_EXPIRY,
        refresh_token: refreshToken
      });
    }
    
    return res.status(400).json({ error: 'unsupported_grant_type', error_description: 'Unsupported grant type' });
  } catch (error) {
    console.error(error);
    return res.status(500).json({ error: 'server_error', error_description: 'Internal server error' });
  }
});

// Validate access token
app.get('/oauth/validate', async (req, res) => {
  try {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return res.status(401).json({ error: 'invalid_token', error_description: 'Invalid authorization header' });
    }
    
    const token = authHeader.substring(7);
    const tokenData = await redisClient.get(`access:${token}`);
    
    if (!tokenData) {
      return res.status(401).json({ error: 'invalid_token', error_description: 'Invalid access token' });
    }
    
    const data = JSON.parse(tokenData);
    if (Date.now() > data.expiresAt) {
      return res.status(401).json({ error: 'invalid_token', error_description: 'Access token expired' });
    }
    
    return res.json({ valid: true, user_id: data.userId });
  } catch (error) {
    console.error(error);
    return res.status(500).json({ error: 'server_error', error_description: 'Internal server error' });
  }
});

